class Solution:
    def minSwaps(self, s: str) -> int:
        n = len(s)
        opening_mismatches = 0
        closing_mismatches = 0
        for bracket in s:
            if bracket == '[':
                if closing_mismatches > 0:
                    closing_mismatches -= 1
                    opening_mismatches += 1
            else:
                if opening_mismatches > 0:
                    opening_mismatches -= 1
                    closing_mismatches += 1
        return opening_mismatches
```
efficiency: HIGH
time complexity: O(n)
